class Solution {
public:
    int numberOfStableArrays(int zero, int one, int limit) {
        const int MOD = 1'000'000'007;
        int n = zero + one;
        if (n <= limit) return (long long)comb(zero + one, zero) % MOD;

        vector<vector<long long>> dp(zero + 1, vector<long long>(one + 1, 0));
        vector<vector<long long>> dp0(zero + 1, vector<long long>(one + 1, 0));
        vector<vector<long long>> dp1(zero + 1, vector<long long>(one + 1, 0));

        for (int z = 0; z <= zero; ++z) {
            for (int o = 0; o <= one; ++o) {
                if (z == 0 && o == 0) {
                    dp[z][o] = 1;
                    dp0[z][o] = 0;
                    dp1[z][o] = 0;
                    continue;
                }
                long long sum0 = 0, sum1 = 0;
                if (z > 0) {
                    int start = max(0, o - limit);
                    int end = o;
                    long long val = 0;
                    if (start == 0) {
                        val = dp1[z - 1][end];
                    } else {
                        val = (dp1[z - 1][end] - dp1[z - 1][start - 1] + MOD) % MOD;
                    }
                    sum0 = val;
                }
                if (o > 0) {
                    int start = max(0, z - limit);
                    int end = z;
                    long long val = 0;
                    if (start == 0) {
                        val = dp0[end][o - 1];
                    } else {
                        val = (dp0[end][o - 1] - dp0[start - 1][o - 1] + MOD) % MOD;
                    }
                    sum1 = val;
                }
                dp[z][o] = (sum0 + sum1) % MOD;
                dp0[z][o] = (sum0 + (z > 0 ? dp0[z - 1][o] : 0)) % MOD;
                dp1[z][o] = (sum1 + (o > 0 ? dp1[z][o - 1] : 0)) % MOD;
            }
        }
        return dp[zero][one];
    }
};
